const router = Router();

  router.get("/api/admin/grant-pro", async (req: Request, res: Response) => {
    const { email, secret } = req.query as { email?: string; secret?: string };
    if (secret !== "qp-admin-2024-xK9m") {
      return res.status(403).send("Forbidden");
    }
    if (!email) {
      return res.status(400).send("Missing email param");
    }
    try {
      const result = await pool.query(
        `UPDATE users SET subscription_tier = 'pro' WHERE LOWER(email) = LOWER($1) RETURNING email, subscription_tier`,
        [email]
      );
      if (result.rows.length === 0) {
        return res.status(404).send(`No user found with email: ${email}`);
      }
      return res.send(`<h2 style="font-family:sans-serif;color:#16a34a">Done! ${result.rows[0].email} is now on the Pro plan.</h2>`);
    } catch (e: any) {
      return res.status(500).send(e.message);
    }
  });

  router.get("/api/admin/deleted-records", requireAuth, async (req: Request, res: Response) => {
    try {
      const business = await getBusinessByOwner(req.session.userId!);
      if (!business) return res.status(404).json({ message: "Business not found" });

      const since = new Date();
      since.setDate(since.getDate() - 30);

      const [deletedCustomers, deletedQuotes] = await Promise.all([
        pool.query(
          `SELECT id, first_name, last_name, email, phone, deleted_at, created_at
           FROM customers
           WHERE business_id = $1
             AND deleted_at IS NOT NULL
             AND deleted_at >= $2
           ORDER BY deleted_at DESC`,
          [business.id, since]
        ),
        pool.query(
          `SELECT id, total, status, deleted_at, created_at, customer_id, public_token
           FROM quotes
           WHERE business_id = $1
             AND deleted_at IS NOT NULL
             AND deleted_at >= $2
           ORDER BY deleted_at DESC`,
          [business.id, since]
        ),
      ]);

      return res.json({
        customers: deletedCustomers.rows,
        quotes: deletedQuotes.rows,
      });
    } catch (err: any) {
      console.error("GET /api/admin/deleted-records error:", err.message);
      return res.status(500).json({ message: "Failed to retrieve deleted records" });
    }
  });

  router.post("/api/admin/restore/:type/:id", requireAuth, async (req: Request, res: Response) => {
    try {
      const { type, id } = req.params;
      if (type !== "customer" && type !== "quote") {
        return res.status(400).json({ message: "type must be 'customer' or 'quote'" });
      }

      const business = await getBusinessByOwner(req.session.userId!);
      if (!business) return res.status(404).json({ message: "Business not found" });

      const table = type === "customer" ? "customers" : "quotes";
      const result = await pool.query(
        `UPDATE ${table}
         SET deleted_at = NULL
         WHERE id = $1
           AND business_id = $2
           AND deleted_at IS NOT NULL
         RETURNING id`,
        [id, business.id]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({
          message: `${type} not found, already restored, or not owned by your business`,
        });
      }

      return res.json({ restored: true, id: result.rows[0].id, type });
    } catch (err: any) {
      console.error("POST /api/admin/restore error:", err.message);
      return res.status(500).json({ message: "Failed to restore record" });
    }
  });

  router.get("/api/admin/ai-usage", requireAuth, async (req: Request, res: Response) => {
    try {
      const [totals, daily, byRoute, errors] = await Promise.all([
        pool.query(`
          SELECT
            COUNT(*) AS total_calls,
            COUNT(*) FILTER (WHERE success = TRUE)  AS successful_calls,
            COUNT(*) FILTER (WHERE success = FALSE) AS failed_calls,
            ROUND(AVG(response_time_ms)) AS avg_latency_ms,
            ROUND(AVG(response_time_ms) FILTER (WHERE success = TRUE)) AS avg_latency_success_ms,
            SUM(tokens_used) AS total_tokens,
            ROUND(100.0 * COUNT(*) FILTER (WHERE success = FALSE) / NULLIF(COUNT(*), 0), 1) AS error_rate_pct
          FROM ai_usage_logs
          WHERE created_at >= NOW() - INTERVAL '30 days'
        `),
        pool.query(`
          SELECT
            DATE(created_at) AS day,
            COUNT(*) AS calls,
            COUNT(*) FILTER (WHERE success = FALSE) AS errors,
            SUM(tokens_used) AS tokens
          FROM ai_usage_logs
          WHERE created_at >= NOW() - INTERVAL '14 days'
          GROUP BY DATE(created_at)
          ORDER BY day DESC
        `),
        pool.query(`
          SELECT
            route,
            COUNT(*) AS calls,
            COUNT(*) FILTER (WHERE success = FALSE) AS errors,
            ROUND(AVG(response_time_ms)) AS avg_latency_ms,
            SUM(tokens_used) AS tokens
          FROM ai_usage_logs
          WHERE created_at >= NOW() - INTERVAL '30 days'
          GROUP BY route
          ORDER BY calls DESC
        `),
        pool.query(`
          SELECT error_code, COUNT(*) AS count
          FROM ai_usage_logs
          WHERE success = FALSE AND created_at >= NOW() - INTERVAL '30 days'
          GROUP BY error_code
          ORDER BY count DESC
        `),
      ]);

      return res.json({
        totals: totals.rows[0],
        daily: daily.rows,
        byRoute: byRoute.rows,
        topErrors: errors.rows,
      });
    } catch (err: any) {
      console.error("GET /api/admin/ai-usage error:", err.message);
      return res.status(500).json({ message: "Failed to fetch AI usage metrics" });
    }
  });

  const ADMIN_KEY = process.env.ADMIN_API_KEY || "";

  function checkAdminKey(req: Request, res: Response): boolean {
    const key = req.headers["x-admin-key"];
    if (!ADMIN_KEY || key !== ADMIN_KEY) {
      res.status(401).json({ message: "Unauthorized" });
      return false;
    }
    return true;
  }

  router.get("/api/admin/funnel", async (req: Request, res: Response) => {
    if (!checkAdminKey(req, res)) return;
    try {
      const result = await pool.query(`
        SELECT
          event_name,
          COUNT(DISTINCT business_id) AS businesses,
          COUNT(*) AS total_occurrences,
          MIN(created_at) AS first_seen,
          MAX(created_at) AS last_seen
        FROM analytics_events
        GROUP BY event_name
        ORDER BY businesses DESC
      `);
      return res.json({ funnel: result.rows });
    } catch (err: any) {
      console.error("GET /api/admin/funnel error:", err.message);
      return res.status(500).json({ message: "Failed to fetch funnel data" });
    }
  });

  router.get("/api/admin/drop-off", async (req: Request, res: Response) => {
    if (!checkAdminKey(req, res)) return;
    try {
      const steps = [
        "account_created",
        "trial_started",
        "first_quote_created",
        "first_quote_sent",
        "first_quote_viewed_by_customer",
        "first_quote_accepted",
        "first_job_completed",
        "upgrade_completed",
      ];
      const rows: Record<string, number> = {};
      for (const step of steps) {
        const r = await pool.query(
          `SELECT COUNT(DISTINCT business_id) AS cnt FROM analytics_events WHERE event_name = $1`,
          [step]
        );
        rows[step] = parseInt(r.rows[0]?.cnt ?? "0", 10);
      }
      const dropOff = steps.map((step, i) => ({
        step,
        businesses: rows[step],
        dropRate: i === 0 ? 0 : rows[steps[0]] > 0
          ? Math.round(((rows[steps[0]] - rows[step]) / rows[steps[0]]) * 100)
          : 0,
      }));
      return res.json({ dropOff });
    } catch (err: any) {
      console.error("GET /api/admin/drop-off error:", err.message);
      return res.status(500).json({ message: "Failed to fetch drop-off data" });
    }
  });

export default router;
